import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import styles from './InstructorPage.module.css';

// ── Helpers ───────────────────────────────────────────────────────────────────
const DAYS = ['ПН', 'ВТ', 'СР', 'ЧТ', 'ПТ', 'СБ', 'ВС'];
const MONTHS = ['ЯНВАРЬ','ФЕВРАЛЬ','МАРТ','АПРЕЛЬ','МАЙ','ИЮНЬ','ИЮЛЬ','АВГУСТ','СЕНТЯБРЬ','ОКТЯБРЬ','НОЯБРЬ','ДЕКАБРЬ'];

function getWeekDays(date) {
  const d = new Date(date);
  const day = d.getDay() || 7;
  d.setDate(d.getDate() - day + 1);
  return Array.from({ length: 7 }, (_, i) => {
    const nd = new Date(d); nd.setDate(d.getDate() + i); return nd;
  });
}

function fmt(d) {
  return `${String(d.getDate()).padStart(2,'0')}.${String(d.getMonth()+1).padStart(2,'0')}.${d.getFullYear()}`;
}

// Mock schedule data
const MOCK_SCHEDULE = [
  { id: 1, start: '09:00', end: '10:30', type: 'theory', title: 'Теоретическое занятие', location: 'Энтузиастов 12, офис 302', color: 'blue' },
  { id: 2, start: '10:30', end: '12:00', type: 'driving', title: 'Иванов Иван Иванович', location: 'Энтузиастов 12, офис 302', color: 'blue' },
  { id: 3, start: '12:00', end: '13:30', type: 'free', title: 'Свободно', location: 'Энтузиастов 12, офис 302', color: 'white' },
];

// ── Component ─────────────────────────────────────────────────────────────────
export default function InstructorPage() {
  const { logout } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('schedule'); // schedule | profile
  const [currentWeekStart, setCurrentWeekStart] = useState(() => {
    const today = new Date();
    const day = today.getDay() || 7;
    const monday = new Date(today);
    monday.setDate(today.getDate() - day + 1);
    return monday;
  });
  const [selectedDate, setSelectedDate] = useState(new Date());

  const weekDays = getWeekDays(currentWeekStart);
  const prevWeek = () => {
    const d = new Date(currentWeekStart); d.setDate(d.getDate() - 7); setCurrentWeekStart(d);
  };
  const nextWeek = () => {
    const d = new Date(currentWeekStart); d.setDate(d.getDate() + 7); setCurrentWeekStart(d);
  };

  // Month label: show both months if week spans two
  const monthLabel = (() => {
    const first = weekDays[0]; const last = weekDays[6];
    if (first.getMonth() === last.getMonth()) return MONTHS[first.getMonth()];
    return `${MONTHS[first.getMonth()]} / ${MONTHS[last.getMonth()]}`;
  })();

  const today = new Date();
  const isToday = (d) => d.toDateString() === today.toDateString();
  const isSelected = (d) => d.toDateString() === selectedDate.toDateString();

  return (
    <div className={styles.app}>
      {/* Content */}
      <div className={styles.content}>

        {activeTab === 'schedule' && (
          <div className={styles.schedulePage}>
            <h1 className={styles.pageTitle}>Расписание</h1>

            {/* Week calendar */}
            <div className={styles.calendarCard}>
              <div className={styles.calendarHeader}>
                <button className={styles.navBtn} onClick={prevWeek}>
                  <span>←</span>
                </button>
                <span className={styles.monthLabel}>{monthLabel}</span>
                <button className={styles.navBtn} onClick={nextWeek}>
                  <span>→</span>
                </button>
              </div>
              <div className={styles.weekRow}>
                {DAYS.map((d) => (
                  <span key={d} className={styles.dayName}>{d}</span>
                ))}
              </div>
              <div className={styles.weekRow}>
                {weekDays.map((d, i) => (
                  <button
                    key={i}
                    className={`${styles.dayBtn} ${isToday(d) ? styles.dayToday : ''} ${isSelected(d) ? styles.daySelected : ''}`}
                    onClick={() => setSelectedDate(d)}
                  >
                    {d.getDate()}
                  </button>
                ))}
              </div>
            </div>

            {/* Day schedule */}
            <div className={styles.dayHeader}>
              <span className={styles.dayDate}>{fmt(selectedDate)}</span>
              <button className={styles.addBtn}>+</button>
            </div>

            <div className={styles.slotList}>
              {MOCK_SCHEDULE.map((slot) => (
                <div
                  key={slot.id}
                  className={`${styles.slot} ${slot.color === 'blue' ? styles.slotBlue : styles.slotWhite}`}
                >
                  <div className={styles.slotTime}>{slot.start} - {slot.end}</div>
                  <div className={styles.slotTitle}>{slot.title}</div>
                  <div className={styles.slotLocation}>
                    <span className={styles.pinIcon}>📍</span>
                    {slot.location}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'profile' && (
          <div className={styles.profilePage}>
            <h1 className={styles.pageTitle}>Профиль</h1>
            <div className={styles.profileCard}>
              <div className={styles.avatar}>
                <span>👤</span>
              </div>
              <div className={styles.profileInfo}>
                <div className={styles.profileName}>Иван И.</div>
                <div className={styles.profileRole}>Инструктор</div>
              </div>
            </div>
            <button className={styles.logoutBtn} onClick={() => { logout(); navigate('/login'); }}>
              Выйти из аккаунта
            </button>
          </div>
        )}
      </div>

      {/* Bottom navigation */}
      <nav className={styles.bottomNav}>
        <button
          className={`${styles.navItem} ${activeTab === 'requests' ? styles.navActive : ''}`}
          onClick={() => setActiveTab('requests')}
        >
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none">
            <path d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
        </button>
        <button
          className={`${styles.navItem} ${activeTab === 'schedule' ? styles.navActive : ''}`}
          onClick={() => setActiveTab('schedule')}
        >
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none">
            <rect x="3" y="4" width="18" height="18" rx="2" ry="2" stroke="currentColor" strokeWidth="2"/>
            <line x1="16" y1="2" x2="16" y2="6" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
            <line x1="8" y1="2" x2="8" y2="6" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
            <line x1="3" y1="10" x2="21" y2="10" stroke="currentColor" strokeWidth="2"/>
